import pytest
import requests

def test_create_procedure_without_encounter_returns_422(
    base_url, auth_headers
):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "subject": {"reference": "Patient/test-patient-1"},
        "code": {
            "coding": [{"system": "http://snomed.info/sct",
                         "code": "80146002",
                         "display": "Appendectomy"}]
        }
    }
    resp = requests.post(
        f"{base_url}/Procedure",
        json=payload,
        headers=auth_headers
    )
    assert resp.status_code == 422
    body = resp.json()
    assert (
        body.get("resourceType") == "OperationOutcome"
        or "encounter" in str(body).lower()
    )

import pytest
import requests

def test_create_procedure_referencing_finished_encounter_boundary(
    base_url, auth_headers, create_encounter, cleanup_resource
):
    encounter_id = create_encounter(status="finished")
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "subject": {"reference": "Patient/test-patient-1"},
        "encounter": {"reference": f"Encounter/{encounter_id}"},
        "code": {
            "coding": [{"system": "http://snomed.info/sct",
                         "code": "80146002",
                         "display": "Appendectomy"}]
        }
    }
    resp = requests.post(
        f"{base_url}/Procedure",
        json=payload,
        headers=auth_headers
    )
    assert resp.status_code in (201, 422), (
        f"Unexpected status {resp.status_code} for finished encounter"
    )
    body = resp.json()
    if resp.status_code == 201:
        assert body["encounter"]["reference"] == f"Encounter/{encounter_id}"
        cleanup_resource("Procedure", body["id"])
    else:
        assert (
            body.get("resourceType") == "OperationOutcome"
            or "encounter" in str(body).lower()
        )
    cleanup_resource("Encounter", encounter_id)
